var mergeKLists = function(lists) {
    // simple binary min-heap of [val, counter, node]
    const heap = [];
    const less = (a, b) => a[0] !== b[0] ? a[0] < b[0] : a[1] < b[1];
    const push = (item) => {
        heap.push(item);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (less(heap[i], heap[p])) { [heap[i], heap[p]] = [heap[p], heap[i]]; i = p; }
            else break;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let i = 0;
            const n = heap.length;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let s = i;
                if (l < n && less(heap[l], heap[s])) s = l;
                if (r < n && less(heap[r], heap[s])) s = r;
                if (s === i) break;
                [heap[i], heap[s]] = [heap[s], heap[i]];
                i = s;
            }
        }
        return top;
    };
    let counter = 0;
    for (const node of lists) {
        if (node) push([node.val, counter++, node]);
    }
    const dummy = new ListNode(0);
    let tail = dummy;
    while (heap.length) {
        const [, , node] = pop();
        tail.next = node;
        tail = node;
        if (node.next) push([node.next.val, counter++, node.next]);
    }
    tail.next = null;
    return dummy.next;
};
